class Process:
    def __init__(self, pid, needed_resources):
        self.pid = pid
        self.needed_resources = needed_resources  # All resources needed
        self.held_resources = []
        self.completed = False

    def request_all_or_wait(self, available_resources):
        """
        Prevent hold and wait by requiring ALL resources at once.
        Process either gets ALL needed or waits.
        """
        can_grant = True
        for res_type, count in self.needed_resources.items():
            if available_resources.get(res_type, 0) < count:
                can_grant = False
                break

        if can_grant:
            # Grant all resources
            for res_type, count in self.needed_resources.items():
                available_resources[res_type] -= count
                self.held_resources.append((res_type, count))
            print(f"Process {self.pid}: All resources granted")
            return True
        else:
            print(f"Process {self.pid}: Waiting - cannot get all resources")
            return False

# Example usage
available = {'printer': 2, 'disk': 3, 'tape': 1}
p1 = Process('P1', {'printer': 1, 'disk': 1, 'tape': 1})
p1.request_all_or_wait(available)  # Will wait if not all available

