#define MAX_RESOURCES 5

typedef struct {
    int resource_id;
    int quantity;
} Resource;

typedef struct {
    int checkpoint_data[100];
    Resource held[MAX_RESOURCES];
    int held_count;
} ProcessState;

// Global checkpoint storage
ProcessState checkpoints[10];

int preempt_resources(int process_id, Resource *held, int held_count) {
    /*
     * Preemption Prevention:
     * When a process cannot get needed resources, 
     * preempt all currently held resources.
     */

    // Save current state as checkpoint
    save_checkpoint(process_id);

    // Return all held resources to available pool
    for (int i = 0; i < held_count; i++) {
        return_resource_to_pool(held[i].resource_id, held[i].quantity);
    }

    // Clear held resources
    held_count = 0;

    printf("Process %d: Resources preempted, added to available pool\n", 
           process_id);
    return 1;  // Preemption successful
}

void save_checkpoint(int process_id) {
    // Save process state to enable rollback
    // In real system, would save register values, memory, etc.
    printf("Checkpoint saved for process %d\n", process_id);
}

int request_with_preemption(int process_id, Resource request, 
                            Resource *held, int *held_count) {
    if (is_resource_available(request.resource_id, request.quantity)) {
        // Grant resource normally
        allocate_resource(process_id, request);
        held[(*held_count)++] = request;
        return 1;
    } else {
        // Cannot grant - preempt held resources
        return preempt_resources(process_id, held, *held_count);
    }
}
